customCSS:
/* Solar Flare - Coronal Mass Ejection */
@import url('https://fonts.googleapis.com/css2?family=Exo+2:wght@300;400;600;700&family=Open+Sans:wght@300;400;600&family=Source+Code+Pro&display=swap');

.cyber-grid {
  background: none;
  animation: none;
}

.cyber-glow {
  background: 
    radial-gradient(ellipse 500px 400px at 50% 0%, rgba(255, 238, 0, 0.15), transparent),
    radial-gradient(ellipse 400px 300px at 50% 0%, rgba(255, 136, 0, 0.08), transparent);
}

.stat-card {
  border: 1px solid rgba(255, 200, 48, 0.12);
  background: rgba(24, 24, 24, 0.95);
}

.stat-card::before {
  background: linear-gradient(90deg, #ffee00, #ff8800, #ff4020);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(255, 238, 0, 0.3);
  box-shadow: 0 0 25px rgba(255, 200, 48, 0.15);
}

.stat-value {
  text-shadow: 0 0 16px rgba(255, 238, 0, 0.5);
}

.celebration-title {
  background: linear-gradient(135deg, #ffee00, #ff8800, #ff4020);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
  filter: drop-shadow(0 0 25px rgba(255, 238, 0, 0.5));
}

.miner-card, .health-card, .lifetime-card {
  border: 1px solid rgba(255, 200, 48, 0.08);
  background: rgba(24, 24, 24, 0.9);
}

.miner-card:hover {
  border-color: rgba(255, 136, 0, 0.2);
}

.logo {
  color: #ffc830;
  text-shadow: 0 0 20px rgba(255, 238, 0, 0.4);
}
